{
  "includeCoAuthoredBy": false,
  "permissions": {
    "deny": [
      "Read(./.entire/metadata/**)"
    ],
    "allow": [
      "Bash(pnpm --filter dashboard add react-day-picker date-fns @radix-ui/react-popover)"
    ]
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Edit|Write|MultiEdit",
        "hooks": [
          {
            "type": "command",
